const get = (id) => cols.find(c => c.id === id) || null;
const split = parseSplit(get('long_text_mm3hgsph')?.text || get('long_text_mm3hgsph')?.value || null);
const cpf = onlyDigits(get('dup__of_matr_cula')?.text || get('dup__of_matr_cula')?.value || '');
const chapa = String(get('texto')?.text || '').trim();
const queryControleAtestados = cpf
  ? 'query { items_page_by_column_values(board_id: 18298015951, columns: [{ column_id: "text_mm3j4nt3", column_values: ["' + cpf + '"] }], limit: 100) { items { id name column_values { id text value column { title } } } } }'
  : null;
return [{ json: { ...base, split, cpf_colaborador: cpf || null, chapa_colaborador: chapa || null, query_controle_atestados: queryControleAtestados } }];

const base = $('Anexar Split').first().json;
const resp = $json;
const controleItems = resp?.data?.items_page_by_column_values?.items || [];
const legacy = Array.isArray(base.atestados) ? base.atestados : [];

