for (const item of controleItems) {
  const modalidade = norm(text(item, 'single_select5yq25pm'));
  if (modalidade && modalidade !== 'INTERMITENTE') continue;
  const inicio = parseDate(item, 'date');
  const dias = Math.max(1, Math.ceil(Number(String(text(item, 'numberjox5johv') || '1').replace(',', '.')) || 1));
  const fim = inicio ? addDays(inicio, dias - 1) : null;
  if (!overlap(inicio, fim, base.data_inicio, base.data_fim)) continue;
  const label = text(item, 'sele__o_individual__1') || 'Atestado';
  const tipoNorm = norm(label);
  const tipoDocumento = tipoNorm.includes('DECLAR') || tipoNorm.startsWith('DC') ? 'declaracao' : 'atestado';
  const fileName = text(item, 'files') || text(item, 'short_textcpcyzaec') || null;
  docsControle.push({
    id: 'controle-' + item.id,
    controle_item_id: String(item.id),
    tipo_documento: tipoDocumento,
    tipo_documentacao_label: label,
    data_inicio: inicio,
    data_fim: fim,
    periodos: [],
    nome_arquivo: fileName,
    monday_item_url: 'https://contato-serv.monday.com/boards/18298015951/pulses/' + item.id,
    origem: 'controle_atestados'
  });
}

const byKey = new Map();
for (const d of legacy) byKey.set(String(d.id || d.monday_item_url || JSON.stringify(d)), d);
for (const d of docsControle) byKey.set(String(d.id), d);
const atestados = [...byKey.values()].sort((a, b) => String(a.data_inicio || '').localeCompare(String(b.data_inicio || '')));
return [{ json: { ...base, atestados, qtd_atestados: atestados.length } }];

